const reply = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';

const hasSpec = reply.includes('---SPEC-START---');
let specNote = '';
if (hasSpec) {
  const m = reply.match(/---SPEC-START---([\s\S]*?)---SPEC-END---/);
  if (m) specNote = '\n\n[Spec extracted. Copy the section above between ---SPEC-START--- and ---SPEC-END--- to use with OpenCode.]';
}

return [{ json: { output: reply + specNote, hasSpec } }];
